n=int(input())
if n<2:print(0)
else:
    sieve=[True]*(n+1)
    sieve[0]=sieve[1]=False
    for i in range(2,int(n**0.5)+1):
        if sieve[i]:
            for j in range(i*i,n+1,i):sieve[j]=False
    print(sum(sieve))

#include<stdio.h>
#include<string.h>
#define MAXN 1000001
char sieve[MAXN];
int main(){int n;scanf("%d",&n);memset(sieve,1,sizeof(sieve));sieve[0]=sieve[1]=0;for(int i=2;(long long)i*i<=n;i++)if(sieve[i])for(int j=i*i;j<=n;j+=i)sieve[j]=0;int cnt=0;for(int i=2;i<=n;i++)cnt+=sieve[i];printf("%d\n",cnt);}

// Naive O(N*sqrt(N)) — slower
#include<stdio.h>
#include<math.h>
int is_prime(int n){if(n<2)return 0;for(int i=2;i<=(int)sqrt(n);i++)if(n%i==0)return 0;return 1;}
int main(){int n;scanf("%d",&n);int cnt=0;for(int i=2;i<=n;i++)if(is_prime(i))cnt++;printf("%d\n",cnt);}
